 237→const extractFromLexical = (contentJson) => {
 238→    try {
 239→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 240→        const texts = [];
 241→        let firstImage = null;
 242→
 243→        const walk = (node) => {
 244→            if (!node || typeof node !== 'object') return;
 245→
 246→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 247→            if (nodeType === 'text' && typeof node.text === 'string') {
 248→                texts.push(node.text);
 249→            }
 250→
 251→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 252→            if (!firstImage && isImageNode) {
 253→                const image = imageFromNodeLike(node);
 254→                if (image) {
 255→                    firstImage = image;
 256→                }
 257→            }
 258→
 259→            if (Array.isArray(node.children)) {
 260→                node.children.forEach(walk);
 261→            }
 262→        };
 263→
 264→        if (parsed?.root) {
 265→            walk(parsed.root);
 266→        }
 267→
 268→        return {
 269→            text: normalizeWhitespace(texts.join(' ')),
 270→            image: firstImage
 271→        };
 272→    } catch {
 273→        return { text: '', image: null };
 274→    }
 275→};
