 361→const isSafeRemoteImageUrl = (imageUrl) => {
 362→    try {
 363→        const parsed = new URL(imageUrl);
 364→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 365→            return false;
 366→        }
 367→
 368→        const hostname = parsed.hostname.toLowerCase();
 369→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 370→            return false;
 371→        }
 372→
 373→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 374→            return false;
 375→        }
 376→
 377→        return true;
 378→    } catch {
 379→        return false;
 380→    }
