 588→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 589→                return;
 590→            }
 591→
 592→            routeStat = {
 593→                count: 0,
 594→                totalDurationMs: 0,
 595→                maxDurationMs: 0,
 596→                bytesSent: 0,
 597→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 598→            };
 599→            metricsState.routeStats.set(routeKey, routeStat);
 600→        }
 601→
 602→        routeStat.count += 1;
 603→        routeStat.totalDurationMs += durationMs;
 604→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 605→        routeStat.bytesSent += byteCount;
 606→        routeStat.statusBuckets[statusBucket] += 1;
 607→    });
 608→
 609→    next();
