239→export const repostService = async(sourceJournalId, caption, userId) => {
240→    if(!sourceJournalId || !userId){
241→        throw {status: 400, error: 'sourceJournalId or userId is undefined'};
242→    }
243→
244→    if(caption && caption.length > 280){
245→        throw {status: 400, error: 'caption must be 280 characters or less'};
246→    }
247→
248→    // Fetch source journal
249→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
250→        .from('journals')
251→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
252→        .eq('id', sourceJournalId)
253→        .maybeSingle();
254→
255→    if(errorSourceJournal){
256→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
257→        throw {status: 500, error: 'supabase error while fetching source journal'};
258→    }
259→
260→    if(!sourceJournal){
261→        throw {status: 404, error: 'source journal not found'};
262→    }
263→
264→    if(sourceJournal.privacy !== 'public'){
265→        throw {status: 403, error: 'cannot repost a private post'};
266→    }
267→
268→    if(sourceJournal.user_id === userId){
269→        throw {status: 403, error: 'cannot repost your own post'};
270→    }
271→
272→    // If reposting a repost, follow chain to the ultimate original
273→    let ultimateSourceId = sourceJournalId;
274→    let ultimateSourceUserId = sourceJournal.user_id;
275→    let ultimateSourceTitle = sourceJournal.title;
276→
277→    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
278→        const {data: originalJournal, error: errorOriginal} = await supabase
279→            .from('journals')
280→            .select('id, title, user_id, privacy')
281→            .eq('id', sourceJournal.repost_source_journal_id)
282→            .maybeSingle();
283→
284→        if(errorOriginal){
285→            console.error('supabase error fetching original:', errorOriginal.message);
286→            throw {status: 500, error: 'supabase error while fetching original post'};
287→        }
288→        if(!originalJournal){
289→            throw {status: 404, error: 'original post no longer exists'};
290→        }
291→        if(originalJournal.privacy !== 'public'){
292→            throw {status: 403, error: 'cannot repost a private post'};
293→        }
294→        if(originalJournal.user_id === userId){
295→            throw {status: 403, error: 'cannot repost your own post'};
296→        }
297→
298→        ultimateSourceId = originalJournal.id;
299→        ultimateSourceUserId = originalJournal.user_id;
300→        ultimateSourceTitle = originalJournal.title;
301→    }
302→
303→    // Check for duplicate repost
304→    const {data: existingRepost, error: errorExisting} = await supabase
305→        .from('journals')
306→        .select('id')
307→        .eq('user_id', userId)
308→        .eq('repost_source_journal_id', ultimateSourceId)
309→        .eq('is_repost', true)
310→        .maybeSingle();
311→
312→    if(errorExisting){
313→        console.error('supabase error while checking existing repost:', errorExisting.message);
314→        throw {status: 500, error: 'supabase error while checking existing repost'};
315→    }
316→
317→    if(existingRepost){
318→        throw {status: 409, error: 'you have already reposted this post'};
319→    }
320→
321→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
322→
323→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
324→        .from('journals')
325→        .insert({
326→            user_id: userId,
327→            is_repost: true,
328→            repost_source_journal_id: ultimateSourceId,
329→            repost_caption: caption || null,
330→            post_type: 'text',
331→            content: null,
332→            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
333→            privacy: 'public'
334→        })
335→        .select('id')
336→        .single();
337→
338→    if(errorInsertRepost){
339→        console.error('supabase error while inserting repost:', errorInsertRepost.message);
340→        throw {status: 500, error: 'supabase error while inserting repost'};
341→    }
342→
343→    // Notify the original author (skip if self)
344→    const isOwnContent = userId === ultimateSourceUserId;
345→    if(!isOwnContent){
346→        const {error: errorNotif} = await supabase
347→            .from('notifications')
348→            .insert({
349→                sender_id: userId,
350→                receiver_id: ultimateSourceUserId,
351→                journal_id: ultimateSourceId,
352→                repost_journal_id: insertedRepost.id,
353→                type: 'repost',
354→                read: false
355→            });
356→
357→        if(errorNotif){
358→            console.error('supabase error while inserting repost notification:', errorNotif.message);
359→        }
360→    }
361→
362→    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
363→}
