 1→const DEFAULT_TIMEOUT_MS = 15000;
 2→const DEFAULT_GET_RETRIES = 2;
 3→const RETRY_BASE_DELAY_MS = 300;
 4→
 5→const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
 6→
 7→const shouldRetryStatus = (status) => status === 408 || status === 429 || status >= 500;
 8→
 9→const isRetryableNetworkError = (error) => {
10→    if (!error) return false;
11→    return error.name === "AbortError" || error instanceof TypeError;
12→};
13→
14→const getBackoffDelay = (attempt) => {
15→    const jitter = Math.floor(Math.random() * 120);
16→    return RETRY_BASE_DELAY_MS * (2 ** attempt) + jitter;
17→};
18→
19→const apiRequest = async (input, init = {}) => {
20→    const method = (init.method || "GET").toUpperCase();
21→    const timeoutMs = init.timeoutMs ?? (method === "GET" ? DEFAULT_TIMEOUT_MS : 0);
22→    const retries = method === "GET" ? (init.retries ?? DEFAULT_GET_RETRIES) : 0;
23→    const { timeoutMs: _, retries: __, signal: callerSignal, ...requestInit } = init;
24→
25→    for (let attempt = 0; attempt <= retries; attempt++) {
26→        const controller = new AbortController();
27→        let timedOut = false;
28→        let timeoutId = null;
29→
30→        const forwardAbort = () => controller.abort();
31→        if (callerSignal) {
32→            if (callerSignal.aborted) {
33→                controller.abort();
34→            } else {
35→                callerSignal.addEventListener("abort", forwardAbort, { once: true });
36→            }
37→        }
38→
39→        if (timeoutMs > 0) {
40→            timeoutId = setTimeout(() => {
41→                timedOut = true;
42→                controller.abort();
43→            }, timeoutMs);
44→        }
45→
46→        try {
47→            const response = await fetch(input, { ...requestInit, signal: controller.signal });
48→
49→            if (attempt < retries && shouldRetryStatus(response.status)) {
50→                await wait(getBackoffDelay(attempt));
51→                continue;
52→            }
53→
54→            return response;
55→        } catch (error) {
56→            if (timedOut) {
57→                throw new Error("Request timed out");
58→            }
59→
60→            if (attempt < retries && isRetryableNetworkError(error)) {
61→                await wait(getBackoffDelay(attempt));
62→                continue;
63→            }
64→
65→            throw error;
66→        } finally {
67→            if (timeoutId) {
68→                clearTimeout(timeoutId);
69→            }
70→            if (callerSignal) {
71→                callerSignal.removeEventListener("abort", forwardAbort);
72→            }
73→        }
74→    }
75→
76→    throw new Error("Request failed");
77→};
78→
79→export default apiRequest;
